test.config:
indexer { mem_limit = 16M }
searchd {
}
source src_bi { type = mysql
sql_query = select * from test_table sql_attr_uint = gid }
index idx_bi { source = src_bi path = /idx_bi
bigram_index = all dict = keywords min_prefix_len = 2 }
index rt_bi { type = rt path = /rt_bi rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = all dict = keywords min_prefix_len = 2 }
index dist_local { type = distributed local = idx_bi local = rt_bi }
index dist_remote { type = distributed agent = :dist_local agent_connect_timeout = 1000 agent_query_timeout = 3000 }
source src_bi2 { type = mysql
sql_query = select * from test_table2 sql_attr_uint = gid }
index idx_bi2 { source = src_bi2 path = /idx_bi2
bigram_index = all dict = keywords min_infix_len = 2 expand_keywords = 1 index_exact_words = 1 morphology = stem_en }
index rt_bi2 { type = rt path = /rt_bi2 rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = all dict = keywords min_infix_len = 2 expand_keywords = 1 index_exact_words = 1 morphology = stem_en }
source src_bi3 { type = mysql
sql_query = select * from test_table3 sql_attr_uint = gid }
index idx_bi3_none { source = src_bi3 path = /idx_bi3_none
bigram_index = all bigram_delimiter = none dict = keywords }
index rt_bi3_none { type = rt path = /rt_bi3_none rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = all bigram_delimiter = none dict = keywords }
index idx_bi3_both { source = src_bi3 path = /idx_bi3_both
bigram_index = all bigram_delimiter = both dict = keywords }
index rt_bi3_both { type = rt path = /rt_bi3_both rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = all bigram_delimiter = both dict = keywords }
index idx_bi3_num { source = src_bi3 path = /idx_bi3_num
bigram_index = second_numeric bigram_delimiter = none dict = keywords }
index rt_bi3_num { type = rt path = /rt_bi3_num rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = second_numeric bigram_delimiter = none dict = keywords }
index idx_bi3_digit { source = src_bi3 path = /idx_bi3_digit
bigram_index = second_has_digit bigram_delimiter = none dict = keywords }
index rt_bi3_digit { type = rt path = /rt_bi3_digit rt_mem_limit = 128k
rt_field = title rt_attr_uint = gid
bigram_index = second_has_digit bigram_delimiter = none dict = keywords }

queries.sphinxql:
INSERT INTO rt_bi (id, gid, title) VALUES ( 1, 1, 'manticore search is the best'), (2, 2, 'manticore is more better' );

CALL KEYWORDS ( 'manti*', 'idx_bi', 1 AS stats, 0 AS fold_wildcards, 'hits' as sort_mode );
CALL KEYWORDS ( 'manti*', 'rt_bi', 1 AS stats, 0 AS fold_wildcards, 'hits' as sort_mode );

FLUSH RAMCHUNK rt_bi;
INSERT INTO rt_bi (id, gid, title) VALUES (3, 3, 'search with manticore like many' );
CALL KEYWORDS ( 'manti*', 'rt_bi', 1 AS stats, 0 AS fold_wildcards, 'hits' as sort_mode );


CALL KEYWORDS ( 'manti*', 'dist_local', 1 AS stats, 0 AS fold_wildcards, 'hits' as sort_mode );
CALL KEYWORDS ( 'manti*', 'dist_remote', 1 AS stats, 0 AS fold_wildcards, 'hits' as sort_mode );


INSERT INTO rt_bi2 (id, gid, title) VALUES ( 1, 1, 'intel i3 10200'), (2, 2, 'intel i5 10500' ), (3, 3, 'intel pentium' );
SELECT * FROM idx_bi2 WHERE MATCH ('*intel*' ) ORDER BY id asc;
SELECT * FROM rt_bi2 WHERE MATCH ('*intel*' ) ORDER BY id asc;

